117	  return (
118	    <Pressable
119	      onPress={onPress}
120	      onPressIn={handlePressIn}
121	      onPressOut={handlePressOut}
122	      accessibilityRole="button"
123	      accessibilityLabel={title}
124	      accessibilityHint={body}
125	      testID={testID}
126	    >
127	      <Animated.View style={[styles.card, shadows.hard, animatedStyle]}>
128	        <View style={[styles.iconSquare, { backgroundColor: accentSoft, borderColor: accent }]}>
129	          <Icon size={32} strokeWidth={2.5} color={accent} />
130	        </View>
131	        <View style={styles.cardText}>
132	          <Text style={[textStyles.h1, styles.cardTitle]}>{title}</Text>
133	          <Text style={[textStyles.body, styles.cardBody]}>{body}</Text>
